#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
    bool validateStackSequences(vector<int>& pushed, vector<int>& popped) { 
        stack<int> s;
        for (int num : pushed) {
            s.push(num);
        }
        for (int num : popped) {
            if (s.empty() || s.top() != num) {
                return false;
            }
            s.pop();
        }
        return s.empty();
    }
};
